136→func (h *Handler) handleHandshake(resp Response, req Request) Response {
137→	resp.Status = "handshake"
138→	resp.FrontendVersion = frontendVersion
139→	resp.Language = frontendLanguage
140→	caps := make([]string, len(CommandCapabilities))
141→	copy(caps, CommandCapabilities)
142→	caps = append(caps,
143→		"complex_type:date", "complex_type:duration", "complex_type:url",
144→		"complex_type:reg_exp", "complex_type:ip_address", "complex_type:big_int",
145→		"complex_type:rational", "complex_type:big_decimal", "complex_type:error",
146→	)
147→	resp.Capabilities = caps
148→	return resp
149→}
