151→func (h *Handler) handleAnalyze(resp Response, req Request) Response {
152→	if req.File == "" {
153→		resp.Status = "error"
154→		resp.Code = ErrInvalidRequest
155→		resp.Message = "analyze command requires a file path"
156→		return resp
157→	}
158→
159→	if _, err := os.Stat(req.File); err != nil {
160→		resp.Status = "error"
161→		resp.Code = ErrFileNotFound
162→		resp.Message = fmt.Sprintf("file not found: %s", req.File)
163→		return resp
164→	}
165→
166→	h.lastAnalyzedFile = req.File
167→
168→	var functionName string
169→	if req.Function != nil {
170→		functionName = *req.Function
171→	}
172→
173→	functions, err := AnalyzeFile(req.File, functionName)
174→	if err != nil {
175→		if functionName != "" && isNotFound(err) {
176→			resp.Status = "error"
177→			resp.Code = "function_not_found"
178→			resp.Message = fmt.Sprintf("function %q not found in %s", functionName, req.File)
179→			return resp
180→		}
181→		resp.Status = "error"
182→		resp.Code = ErrParseError
183→		resp.Message = err.Error()
184→		return resp
185→	}
186→
187→	resp.Status = "analyze"
188→	if functions == nil {
189→		functions = []FunctionAnalysis{}
190→	}
191→	resp.Functions = functions
192→	return resp
193→}
194→
195→func isNotFound(err error) bool {
196→	return err != nil && strings.HasPrefix(err.Error(), "function not found")
197→}
