199→func (h *Handler) handleInstrument(resp Response, req Request) Response {
200→	if req.File == "" {
201→		resp.Status = "error"
202→		resp.Code = ErrInvalidRequest
203→		resp.Message = "instrument command requires a file path"
204→		return resp
205→	}
206→
207→	if _, err := os.Stat(req.File); err != nil {
208→		resp.Status = "error"
209→		resp.Code = ErrFileNotFound
210→		resp.Message = fmt.Sprintf("file not found: %s", req.File)
211→		return resp
212→	}
213→
214→	h.lastAnalyzedFile = req.File
215→
216→	outputDir, err := instrument.InstrumentFile(req.File, req.Function, req.ProjectRoot)
217→	if err != nil {
218→		resp.Status = "error"
219→		resp.Code = ErrInternalError
220→		resp.Message = fmt.Sprintf("instrumentation failed: %v", err)
221→		return resp
222→	}
223→
224→	instrumented := true
225→	resp.Status = "instrument"
226→	resp.Instrumented = &instrumented
227→	resp.OutputFile = &outputDir
228→	return resp
229→}
