231→func (h *Handler) handleExecute(resp Response, req Request) Response {
232→	file := req.File
233→	if file == "" {
234→		file = h.lastAnalyzedFile
235→	}
236→	if file == "" {
237→		resp.Status = "error"
238→		resp.Code = ErrInvalidRequest
239→		resp.Message = "execute command requires a file path (or a prior analyze)"
240→		return resp
241→	}
242→
243→	if req.Function == nil || *req.Function == "" {
244→		resp.Status = "error"
245→		resp.Code = ErrInvalidRequest
246→		resp.Message = "execute command requires a function name"
247→		return resp
248→	}
249→
250→	if _, err := os.Stat(file); err != nil {
251→		resp.Status = "error"
252→		resp.Code = ErrFileNotFound
253→		resp.Message = fmt.Sprintf("file not found: %s", file)
254→		return resp
255→	}
256→
257→	// Convert protocol MockConfigs to instrument MockConfigs and pass to executor.
258→	var execMocks []instrument.MockConfig
259→	for _, m := range req.Mocks {
260→		execMocks = append(execMocks, instrument.MockConfig{
261→			Symbol:           m.Symbol,
262→			ReturnValues:     m.ReturnValues,
263→			ShouldTrackCalls: m.ShouldTrackCalls,
264→			DefaultBehavior:  m.DefaultBehavior,
265→		})
266→	}
267→	result, err := instrument.ExecuteFunction(file, *req.Function, req.Inputs, execMocks)
268→	if err != nil {
269→		resp.Status = "error"
270→		if strings.Contains(err.Error(), "function not found") {
271→			resp.Code = "function_not_found"
272→		} else if strings.Contains(err.Error(), "build failed") {
273→			resp.Code = "instrumentation_failed"
274→		} else if strings.Contains(err.Error(), "timed out") {
275→			resp.Code = ErrExecutionTimeout
276→		} else {
277→			resp.Code = ErrInternalError
278→		}
279→		resp.Message = err.Error()
280→		return resp
281→	}
282→
283→	resp.Status = "execute"
284→	resp.ReturnValue = result.ReturnValue
285→	resp.ThrownError = convertErrorInfo(result.ThrownError)
286→	resp.LinesExecuted = toIntSlice(result.LinesExecuted)
287→	resp.BranchPath = convertBranchPath(result.BranchPath)
288→	resp.PathConstraints = extractPathConstraints(result.BranchPath)
289→	resp.CallsToExternal = convertExternalCalls(result.ExternalCalls)
290→	resp.SideEffects = convertSideEffects(result.SideEffects)
291→	resp.ScopeEvents = result.ScopeEvents
292→	resp.Performance = &PerfMetrics{
293→		WallTimeMs:         result.Performance.WallTimeMs,
294→		CPUTimeUs:          result.Performance.CPUTimeUs,
295→		HeapUsedBytes:      result.Performance.HeapUsedBytes,
296→		HeapAllocatedBytes: result.Performance.HeapAllocatedBytes,
297→	}
298→
299→	return resp
300→}
301→
302→func convertErrorInfo(e *instrument.ErrorInfo) *ErrorInfo {
303→	if e == nil {
304→		return nil
305→	}
306→	var stack *string
307→	if e.Stack != "" {
308→		stack = &e.Stack
309→	}
310→	return &ErrorInfo{
311→		ErrorType: e.ErrorType,
312→		Message:   e.Message,
313→		Stack:     stack,
314→	}
315→}
316→
317→func toIntSlice(ints []int) []int {
318→	if ints == nil {
319→		return []int{}
320→	}
321→	return ints
322→}
323→
324→func convertBranchPath(branches []instrument.BranchDecision) []BranchDecision {
325→	result := make([]BranchDecision, len(branches))
326→	for i, b := range branches {
327→		constraint := &SymConstraint{Kind: "unknown", Hint: "no symbolic constraint from Go frontend"}
328→		if b.ConstraintJSON != "" {
329→			var sc SymConstraint
330→			if err := json.Unmarshal([]byte(b.ConstraintJSON), &sc); err == nil {
331→				constraint = &sc
332→			}
333→		}
334→		result[i] = BranchDecision{
335→			BranchID:   b.BranchID,
336→			Line:       b.Line,
337→			Taken:      b.Taken,
338→			Constraint: constraint,
339→		}
340→	}
341→	return result
342→}
343→
344→func extractPathConstraints(branches []instrument.BranchDecision) []SymConstraint {
345→	var constraints []SymConstraint
346→	for _, b := range branches {
347→		if b.ConstraintJSON == "" {
348→			continue
349→		}
350→		var sc SymConstraint
351→		if err := json.Unmarshal([]byte(b.ConstraintJSON), &sc); err == nil {
352→			constraints = append(constraints, sc)
353→		}
354→	}
355→	if constraints == nil {
356→		return []SymConstraint{}
357→	}
358→	return constraints
359→}
360→
361→// convertExternalCalls converts executor ExternalCall records to protocol format.
362→func convertExternalCalls(calls []instrument.ExternalCall) []ExternalCall {
363→	if len(calls) == 0 {
364→		return []ExternalCall{}
365→	}
366→	result := make([]ExternalCall, len(calls))
367→	for i, c := range calls {
368→		var args []any
369→		if c.Args != nil {
370→			json.Unmarshal(c.Args, &args) //nolint:errcheck
371→		}
372→		var retVal any
373→		if c.ReturnValue != nil {
374→			json.Unmarshal(c.ReturnValue, &retVal) //nolint:errcheck
375→		}
376→		result[i] = ExternalCall{
377→			Symbol:      c.Symbol,
378→			Args:        args,
379→			ReturnValue: retVal,
380→		}
381→	}
382→	return result
383→}
384→
385→// convertSideEffects converts executor SideEffects to protocol format.
386→func convertSideEffects(effects []instrument.SideEffect) []SideEffect {
387→	if len(effects) == 0 {
388→		return []SideEffect{}
389→	}
390→	result := make([]SideEffect, len(effects))
391→	for i, e := range effects {
392→		result[i] = SideEffect{
393→			Kind:    e.Kind,
394→			Level:   e.Level,
395→			Message: e.Message,
396→		}
397→	}
398→	return result
399→}
