401→func (h *Handler) handleSetup(resp Response, req Request) Response {
402→	if req.File == "" {
403→		resp.Status = "error"
404→		resp.Code = ErrInvalidRequest
405→		resp.Message = "setup command requires a file path"
406→		return resp
407→	}
408→	if req.Scope == "" {
409→		resp.Status = "error"
410→		resp.Code = ErrInvalidRequest
411→		resp.Message = "setup command requires a scope"
412→		return resp
413→	}
414→	if !req.Level.IsValid() {
415→		resp.Status = "error"
416→		resp.Code = ErrInvalidRequest
417→		resp.Message = fmt.Sprintf("setup command requires a valid level, got %q", req.Level)
418→		return resp
419→	}
420→
421→	if _, err := os.Stat(req.File); err != nil {
422→		resp.Status = "error"
423→		resp.Code = ErrFileNotFound
424→		resp.Message = fmt.Sprintf("setup file not found: %s", req.File)
425→		return resp
426→	}
427→
428→	var parentCtxJSON json.RawMessage
429→	if req.ParentContext != nil {
430→		data, err := json.Marshal(req.ParentContext)
431→		if err != nil {
432→			resp.Status = "error"
433→			resp.Code = ErrInternalError
434→			resp.Message = fmt.Sprintf("marshaling parent context: %v", err)
435→			return resp
436→		}
437→		parentCtxJSON = data
438→	}
439→
440→	h.log.Debug("Running setup", "file", req.File, "scope", req.Scope, "level", req.Level)
441→
442→	ctx, err := h.setupLoader.RunSetup(req.File, req.Scope, string(req.Level), req.ProjectRoot, parentCtxJSON)
443→	if err != nil {
444→		resp.Status = "error"
445→		resp.Code = ErrInternalError
446→		resp.Message = fmt.Sprintf("setup failed: %v", err)
447→		return resp
448→	}
449→
450→	resp.Status = "setup"
451→	ctxCopy := json.RawMessage(ctx)
452→	resp.SetupContext = &ctxCopy
453→	return resp
454→}
455→
456→func (h *Handler) handleTeardown(resp Response, req Request) Response {
457→	if req.Scope == "" {
458→		resp.Status = "error"
459→		resp.Code = ErrInvalidRequest
460→		resp.Message = "teardown command requires a scope"
461→		return resp
462→	}
463→	if !req.Level.IsValid() {
464→		resp.Status = "error"
465→		resp.Code = ErrInvalidRequest
466→		resp.Message = fmt.Sprintf("teardown command requires a valid level, got %q", req.Level)
467→		return resp
468→	}
469→
470→	h.log.Debug("Running teardown", "scope", req.Scope, "level", req.Level)
471→
472→	h.setupLoader.Teardown(req.Scope, string(req.Level))
473→
474→	resp.Status = "teardown_ack"
475→	return resp
476→}
477→
478→func (h *Handler) handleGenerate(resp Response, req Request) Response {
479→	if req.File == "" {
480→		resp.Status = "error"
481→		resp.Code = ErrInvalidRequest
482→		resp.Message = "generate command requires a file path"
483→		return resp
484→	}
485→	if req.Name == "" {
486→		resp.Status = "error"
487→		resp.Code = ErrInvalidRequest
488→		resp.Message = "generate command requires a name"
489→		return resp
490→	}
491→
492→	var recipe json.RawMessage
493→	if req.Recipe != nil {
494→		recipe = *req.Recipe
495→	}
496→
497→	value, generatorID, outRecipe, err := h.registry.Generate(req.File, req.Name, recipe)
498→	if err != nil {
499→		resp.Status = "error"
500→		resp.Code = ErrInternalError
501→		resp.Message = fmt.Sprintf("generate failed: %v", err)
502→		return resp
503→	}
504→
505→	resp.Status = "generate"
506→	valCopy := json.RawMessage(value)
507→	resp.Value = &valCopy
508→	resp.GeneratorID = generatorID
509→	if outRecipe != nil {
510→		recipeCopy := json.RawMessage(outRecipe)
511→		resp.Recipe = &recipeCopy
512→	}
513→	return resp
514→}
515→
516→// Registry returns the generator registry, allowing custom builds to register
517→// native generators before calling Run().
518→func (h *Handler) Registry() *generators.Registry {
519→	return h.registry
520→}
521→
522→func (h *Handler) handleShutdown(resp Response) Response {
523→	h.registry.Close()
524→	h.setupLoader.Close()
525→	resp.Status = "shutdown_ack"
526→	return resp
527→}
528→
529→func (h *Handler) send(resp Response) error {
530→	data, err := json.Marshal(resp)
531→	if err != nil {
532→		return fmt.Errorf("marshaling response: %w", err)
533→	}
534→	line := string(data) + "\n"
535→	h.log.Log(context.Background(), LevelTrace, "Sent", "raw", string(data))
536→	_, err = io.WriteString(h.writer, line)
537→	return err
538→}
