	if err := os.WriteFile(tmp, []byte(src), 0644); err != nil {
		t.Fatal(err)
	}
	req := reqJSON(3, "analyze", fmt.Sprintf(`"file":"%s"`, tmp))
	resp := sendRecv(t, req)
	if resp.Status != "analyze" {
